import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testWithRecordSeparator_char() throws Exception {
        CSVFormat baseFormat = CSVFormat.DEFAULT;

        // Test with '\n'
        CSVFormat formatLf = baseFormat.withRecordSeparator('\n');
        assertNotNull(formatLf);
        assertEquals("\n", formatLf.getRecordSeparator());

        // Test with '\r'
        CSVFormat formatCr = baseFormat.withRecordSeparator('\r');
        assertNotNull(formatCr);
        assertEquals("\r", formatCr.getRecordSeparator());

        // Test with multi-char separator using char array (simulate edge case)
        // Since method accepts char, only single char is possible,
        // so test with unusual char
        CSVFormat formatTab = baseFormat.withRecordSeparator('\t');
        assertNotNull(formatTab);
        assertEquals("\t", formatTab.getRecordSeparator());

        // Test that original instance is not mutated
        assertNotEquals(baseFormat.getRecordSeparator(), formatLf.getRecordSeparator());
        assertNotEquals(baseFormat.getRecordSeparator(), formatCr.getRecordSeparator());
        assertNotEquals(baseFormat.getRecordSeparator(), formatTab.getRecordSeparator());
    }
}
